			fail("Expected IllegalArgumentException to be thrown");
		} catch (IllegalArgumentException e) {
			assertEquals("You must provide a callback url", e.getMessage());
		} catch (org.jinstagram.exceptions.InstagramException e) {
			// If an InstagramException is thrown, check if it wraps an IllegalArgumentException
			Throwable cause = e.getCause();
			if (cause instanceof IllegalArgumentException) {
				assertEquals("You must provide a callback url", cause.getMessage());
			} else {
				throw e; // rethrow if it's not the expected wrapped exception
			}
		}
	}

}

