import org.junit.Test;

public class RequestTest {

    @Test
    public void testGetQueryStringParamsCorrectlyParsesAndCombinesParameters() {
        // Precondition 1: Initialize with a URL containing query parameters
        Request request = new Request(Verbs.GET, "http://example.com/api?existing1=val1&existing2=val2");

        // Precondition 2: Add extra query string parameters
        request.addQuerystringParameter("extra1", "extraVal1");
        request.addQuerystringParameter("extra2", "extraVal2");

        // Execute the method under test
        Map<String, String> result = request.getQueryStringParams();

        // Expected Result 1: The resulting map is not null
        assertNotNull(result);

        // Expected Result 2: Map includes all expected parameters from the URL
        assertEquals("val1", result.get("existing1"));
        assertEquals("val2", result.get("existing2"));

        // Expected Result 2 (continued): Map includes all extra parameters provided
        assertEquals("extraVal1", result.get("extra1"));
        assertEquals("extraVal2", result.get("extra2"));

        // Verify the total number of parameters
        assertEquals(4, result.size());

        // Additional check to ensure no unexpected parameters are present
        assertTrue(result.containsKey("existing1"));
        assertTrue(result.containsKey("existing2"));
        assertTrue(result.containsKey("extra1"));
        assertTrue(result.containsKey("extra2"));
    }

}

